INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('bestellung.behandlung.sepa.body', 'Behandlung: SEPA-/Bestell-Hinweistext', '<p>Mit der Bestellung beauftrage ich den Vorstand des Bienenzuchtvereins Grünberg, die Oxalsäure in meinem Namen mitzubestellen. Ich ermächtige den Verein, den fälligen Betrag mittels SEPA-Lastschrift von meinem oben angegebenen Konto einzuziehen. Zugleich weise ich mein Kreditinstitut an, die Lastschrift einzulösen.</p>');
