INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('bildnachweis.footer', 'Bildnachweis: Lizenz-Hinweis am Ende', '<h2>Lizenz-Informationen</h2><p>Die meisten Bilder stehen unter <strong>Creative Commons</strong>-Lizenzen (CC BY-SA 3.0 / 4.0) bzw. sind <strong>Public Domain</strong>. Bei der Weiterverwendung sind jeweils Urheber, Lizenz und Quelle anzugeben — eine Verlinkung auf die Wikimedia-Commons-Datei erfüllt diese Anforderung.</p>');
