INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('datenschutz.body', 'Datenschutz: Lauftext', '<h2>Verantwortlicher</h2><p>Bienenzuchtverein Grünberg, vertreten durch den Vorstand<br>[Vereinsanschrift]</p><h2>Erhobene Daten</h2><p>Beim Aufruf dieser Webseite werden vom Hosting-Provider technisch notwendige Server-Logs gespeichert (IP-Adresse, Datum, Uhrzeit, abgerufene Datei). Diese werden ausschließlich zur Gewährleistung des sicheren und stabilen Betriebs der Webseite erhoben und verarbeitet.</p><h2>Formulare</h2><p>Bei Nutzung des Schwarm-Meldeformulars oder des Beitritts-Formulars werden die von Ihnen eingegebenen Daten ausschließlich zur Bearbeitung Ihres Anliegens per E-Mail an den Vereinsvorstand übermittelt und zur Bearbeitung temporär oder dauerhaft im Vereinssystem verarbeitet. Eine Weitergabe an unbefugte Dritte erfolgt nicht.</p><h2>Cookies</h2><p>Wir verwenden ausschließlich technisch notwendige Session-Cookies für den geschützten Login-Bereich. Es werden zu keinem Zeitpunkt Tracking-, Analyse- oder Marketing-Cookies eingesetzt.</p><h2>Externe Ressourcen</h2><p>Diese Webseite lädt das CSS-Framework <em>Tailwind</em> über ein öffentliches CDN. Beim Laden der Seite wird eine technische Verbindung zum Server des CDN-Anbieters aufgebaut. Externe YouTube-Videos auf unserer Informationsseite werden erst nach Ihrer ausdrücklichen Bestätigung (Klick) geladen.</p><h2>Ihre Rechte</h2><p>Sie haben jederzeit das gesetzliche Recht auf kostenfreie Auskunft, Berichtigung, Sperrung oder Löschung Ihrer gespeicherten personenbezogenen Daten. Wenden Sie sich hierzu vertrauensvoll an den Vorstand.</p>');
INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('footer.kontakt.body', 'Footer: Außerhalb-Saison-Text', 'Fragen zur Imkerei, Mitgliedschaft oder unserem Verein? Wir freuen uns auf Ihre Nachricht.');
