INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('home.intro.body', 'Startseite: Begrüßungstext (von alter Seite)', '<h2 style=\"text-align: center;\"><strong>Herzlich Willkommen auf der Homepage des Bienenzuchtvereins Grünberg und Umgebung e.V.</strong></h2><p><strong>Es freut uns, dass Sie den Weg zu uns gefunden haben.</strong></p><p><strong>Wir haben etwas Besonderes gemeinsam: Wir interessieren uns für ein ganz besonderes Tier: Ein Insekt, dass große Bedeutung für uns alle hat: Die Honigbiene (Apis Mellifera).</strong></p><p><strong>Uns hat das dazu bewegt, unsere Freizeit mit unseren und für unsere Bienen zu verbringen. Das geht auch ganz allein - aber mit vereinten Kräften geht das noch viel besser!</strong></p><p><strong>Es ist nämlich ein wunderbares Hobby, aber auch ein anspruchsvolles, denn <em>Bienenhaltung ist Tierhaltung und Tierhaltung fordert selbstverständlich Verantwortung</em>. Neben der Beachtung der vielfältigen Verpflichtungen für das Tierwohl unserer Bienen dürfen wir aber auch die wundervollen Produkte ihrer fleißigen Arbeit ernten: Honig, Wachs und Weitere.</strong></p><p><strong>Als Imker wissen wir auch, wie wichtig unsere Tiere für die Natur sind. Vor allem ist dabei die Bestäubungsleistung von Nutz- und Wildpflanzen zu nennen. Der Deutsche Imkerbund gibt an, dass etwa 85 % der landwirtschaftlichen Erträge des Pflanzen- und Obstbaus von der Bestäubung durch die Honigbiene abhängig seien.</strong></p><p><strong>Um immer auf dem neusten Stand zu bleiben, geben wir uns Mühe, unseren Mitgliedern Weiterbildungen und Schulungen zugänglich zu machen. Dafür treffen wir uns nach Möglichkeit monatlich in Versammlungen und mehrmals im Jahr zu Vorträgen bzw. Standschauen bei unseren Mitgliedern. Drei unserer Mitglieder dürfen sich Imkerberater nennen. Sie werden regelmässig in Lehrgängen vom LLH- Bieneninstitut Kirchhain geschult und sind im regen Kontakt mit diesem. Auch dürfen wir zwei Bienensachverständige unter unseren Mitgliedern zählen. In unseren Monatsversammlungen finden kleinere Vorträge zu aktuellen Themen, passend zum Bienenjahr, statt.</strong></p><p><strong>Auf dieser Seite finden Sie auch gute Informationen. Dafür gerne auf \"Tipps für Imker\" oder auch \"Aktuelles\" klicken.</strong></p><p><strong>Falls Sie Interesse an Bienen und/oder Imkerei haben, wenden Sie sich sehr gerne an unseren Vorstand oder nehmen Sie <a href=\"mailto:info@bienenzuchtverein-gruenberg.de\">Kontakt</a> zu einem Imker in Ihrer Nähe auf. Dort bekommen Sie unter anderem umfassende Informationen zu unserem \"Einsteigerprogramm\".</strong></p><p><strong>Sie dürfen uns auch sehr gerne zu unseren Monatsversammlungen besuchen. Die aktuellen Versammlungstermine und -orte finden Sie unter <a href=\"/index.php/termine\">Termine</a>.</strong></p>');
