INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('home.welcome.body', 'Startseite: Willkommens-Text (Hero)', '<p>Schön, dass Sie hier sind! Wir sind eine engagierte Gemeinschaft von Imkerinnen und Imkern in Grünberg und Umgebung – mit Leidenschaft für die Honigbiene und ihren Beitrag zu unserer Natur.</p><p>Bei uns finden Sie Ansprechpartner für Bienenhaltung, Standverkauf, Schwarmrettung und alles, was rund um die Imkerei wichtig ist – egal ob Sie selbst imkern möchten, regionalen Honig suchen oder einen Schwarm in Ihrem Garten entdeckt haben.</p>');
INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('imker.empty', 'Imker-Karte: leer-Hinweis', 'Aktuell sind noch keine Imker auf der Karte eingetragen. Sind Sie Imker und möchten hier erscheinen? Sprechen Sie den Vorstand an.');
INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('imker.eyebrow', 'Honigkauf-Seite: Eyebrow', 'Honig direkt vom Imker');
INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('imker.honig_preis', 'Honigkauf-Seite: Preis-Erklärung', '<p><strong>Was kostet ein Glas?</strong> Aktuell liegt der Preis für 500 g Honig bei unseren Imkerinnen und Imkern <strong>zwischen 6 und 7 €</strong>.</p><p>In diesem Glas steckt mehr als Honig: ein Jahr Arbeit mit den Bienen, regelmäßige Kontrollen, Pflege der Völker, Varroabehandlung, Standortbetreuung, Ernte, Schleudern, Rühren, Abfüllen und Etikettieren.</p><p>Unsere Bienen sammeln den Honig — aber die Imkerin oder der Imker sorgt dafür, dass sie gesund bleiben und der Honig sorgfältig ins Glas kommt.</p><p>Dazu gehört auch die regelmäßige Weiterbildung: Viele Imkerinnen und Imker besuchen Honigkurse, die sie selbst bezahlen. Dort werden unter anderem hygienische Standards, die sachgerechte Verarbeitung und die Qualitätsanforderungen für Honig vermittelt. So wird sichergestellt, dass der Honig nicht nur gut schmeckt, sondern auch sorgfältig und sauber verarbeitet wird.</p><p><em>Regional, handgemacht und direkt vom Imker.</em></p>');
INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('imker.subtitle', 'Honigkauf-Seite: Untertitel', 'Hier finden Sie unsere Vereinsimkerinnen und -imker, die Honig direkt vom Stand anbieten. Schwarmhelfer sind ebenfalls markiert.');
