INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('impressum.body', 'Impressum: Lauftext', '<div><br><strong>Angaben gemäß § 5 TMG</strong></div><div><br>Bienenzuchtverein Grünberg und Umgebung e.V.<br>&nbsp;Wirberger Straße 14<br>&nbsp;35447 Reiskirchen</div><div>Telefon: 06401/228285<br>&nbsp;E-Mail:<a href=\"mailto:info@bienenzuchtverein-gruenberg.de\"> info@bienenzuchtverein-gruenberg.de</a></div><div><br><strong>Vertreten durch</strong></div><div>1. Vorsitzender: Samuel Krutzky<br><br><strong>Registereintrag:</strong><br> Eingetragen im Vereinsregister.<br> Registergericht: Amtsgericht Giessen<br> Registernummer: 2371<br><br><strong>Bankverbindung:<br></strong>Sparkasse Grünberg, DE69 5135 1526 0000 0108 92</div><div>BIC: HELADEF1GRU</div><div><br><br></div><div><strong>Haftungsausschluss</strong></div><div>Trotz sorgfältiger inhaltlicher Kontrolle übernehmen wir keine Haftung für die Inhalte externer Links. Für den Inhalt der verlinkten Seiten sind ausschließlich deren Betreiber verantwortlich.</div>');
