INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('mitglied.intro', 'Mitglied-werden: Einleitungstext', 'Schön, dass Sie sich für eine Mitgliedschaft beim Bienenzuchtverein Grünberg interessieren! Ob aktiver Imker oder passiver Förderer — jeder ist herzlich willkommen.');
INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('mitglied.rollen.body', 'Mitglied werden: Rollen-Beschreibung (HTML mit Liste)', '<p>Ein lebendiger Verein lebt von <strong>vielen Händen</strong> — nicht nur von Imkerinnen und Imkern. Auch wenn Sie keinen eigenen Bienenstand betreiben, freuen wir uns sehr über Ihre Unterstützung. Besonders brauchen wir:</p><ul><li><strong>Standverkäuferinnen und Standverkäufer</strong> für unsere Auftritte auf Veranstaltungen wie „Grünberg auf der Rolle\" und anderen regionalen Festen</li><li><strong>Kassiererinnen und Kassierer sowie Organisationstalente</strong>, die uns bei der Vereinsführung und Buchhaltung unter die Arme greifen</li><li><strong>Helferinnen und Helfer bei Vereins-Events</strong>, von der Standschau bis zur Honigverkostung</li><li><strong>Fördermitglieder</strong>, die unsere Arbeit ideell und mit ihrem Jahresbeitrag unterstützen — ohne aktive Mitarbeit</li></ul><p>Sprechen Sie uns gerne an: jede Form von Engagement ist willkommen.</p>');
INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('mitglied.rollen.title', 'Mitglied werden: Rollen-Hervorhebung Überschrift', 'Auch ohne eigene Bienen herzlich willkommen');
