INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('mitglied.verein.body', 'Mitglied werden: Vereinsvorstellung-Text (HTML)', '<p>Der <strong>Bienenzuchtverein Grünberg</strong> blickt auf eine traditionsreiche Geschichte zurück und widmet sich leidenschaftlich dem Schutz von Honigbienen, Wildbienen und unseren Ökosystemen. Wir verbinden gelebte Imkertradition mit fundiertem Fachwissen.</p><p>Unsere Mitglieder treffen sich regelmäßig zu <strong>Monatsversammlungen, Standschauen und Schulungen</strong>. Wir bieten Einsteigern eine fundierte Begleitung in die Imkerei und erfahrenen Imkern fachliche Weiterbildung, einen lebendigen Erfahrungsaustausch und Unterstützung bei Bienengesundheit und Schwarmrettung.</p>');
INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('mitglied.verein.title', 'Mitglied werden: Vereinsvorstellung-Überschrift', 'Was uns ausmacht');
INSERT INTO `page_blocks` (`slug`, `title`, `body`) VALUES ('schwarm.calm.body', 'Schwarm: Hinweis-Box Verhaltenshinweise', '<p><strong>Schwärme sind nicht gefährlich.</strong> Ein abgehender Bienenschwarm hat weder Brut noch Honig zu verteidigen und ist deutlich friedlicher als ein normales Bienenvolk. Stechgefahr besteht nur, wenn die Tiere bedrängt werden.</p><p><strong>Was Sie tun können — und was nicht:</strong></p><ul><li>Halten Sie Abstand, lassen Sie die Bienen in Ruhe hängen.</li><li>Verständigen Sie uns telefonisch oder über das Formular weiter unten.</li><li>Bitte <strong>nicht</strong> mit Wasser bespritzen, mit Rauch oder Insektenspray bekämpfen.</li><li>Bitte <strong>nicht</strong> die Feuerwehr rufen — Bienen sind Nutztiere, kein Feuerwehrfall. Die Wehr verweist ohnehin an uns Imker weiter.</li><li>Kinder und Haustiere vom Schwarm fernhalten, damit niemand erschreckt wird.</li></ul><p><strong>Zeit ist wichtig, aber meist genug da:</strong> Ein Schwarm bleibt typischerweise einige Stunden bis zu einem Tag an seinem Sammelplatz, bevor er weiterzieht. Je früher Sie sich melden, desto sicherer können wir ihn einfangen. Sollten wir nicht sofort reagieren — der Schwarm bleibt in der Regel ruhig, bitte einfach abwarten.</p><p>Eine genaue <strong>Standort-Angabe</strong> und idealerweise ein <strong>Foto</strong> helfen uns enorm, das passende Werkzeug (Leiter, Schwarmfangkiste) mitzubringen.</p>');
