INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('gruenberger-imker-und-bienenzuchtverein-auf-honigtag-geehrt', 'Grünberger Imker und Bienenzuchtverein auf Honigtag geehrt', '2024-12-20', NULL, 'news/2024/d55039d130a66c42.jpg', '<div>Einmal im Jahr kürt der Landesverband hessischer Imker (LHI) die besten Honige des Landes beim hessischen Honigtag. Dieses Jahr fand die Veranstaltung in der malerischen Stadt Langen statt und bot eine schöne Kulisse für Imker und Honigliebhaber von nah und fern.</div><div>Die Besucher wurden zunächst mit einem informativen Vortrag zum Thema „Honiggewinnung in Zeiten des Klimawandels“ begrüßt. Der Referent Klaus Körber von der bayerischen Landesanstalt für Weinbau und Gartenbau sprach über die Herausforderungen bei der Auswahl von Trachtpflanzen, die auch in Zukunft die Nahrungsgrundlage für Bienen sichern können.</div><div>Anschließend wurde es spannend: Die besten Honige Hessens wurden ausgezeichnet. Zur Honigprüfung hatten Imker aus dem ganzen Land Honige eingereicht. Der Bienenzuchtverein Grünberg und Umgebung e.V. war auch in diesem Jahr wieder sehr erfolgreich. Die Honige von Dirk Münster, Anja Schnecko, Werner Bugdahl, Samuel Krutzky und Holger Kühn wurden jeweils mit einer Silbermedaille geehrt. Besonders stolz konnte der Verein auf die Goldmedaillen für die Honige von Max Köhler, Dirk Münster, Werner Bugdahl, Stefan Böck und beide eingereichten Honige von Steffi Kratz sein. Zusätzlich kam dem Bienenzuchtverein Grünberg noch eine besondere Ehrung zu. Er wurde für die aktivste Teilnahme an der Prämierung (Einreichungen im Verhältnis zur Mitgliederzahl) hessenweit ausgezeichnet.</div><div>Die Verleihung der Urkunden und Laborberichte zu den Honigproben rundete den offiziellen Teil des Honigtages ab. Besucher hatten anschließend die Möglichkeit, sich untereinander auszutauschen. So war der hessische Honigtag nicht nur eine Feier der besten Honige, sondern auch ein Treffpunkt für Imker, um ihre Erfahrungen zu teilen und zu lernen.</div><div>Zum Jahresabschluss trafen sich die Mitglieder des Bienenzuchtvereins nur wenig später zu ihrem traditionellen Adventscafe, diesmal im Kaffeehaus der Bäckerei Künkel in Grünberg. In seiner Ansprache ließ der erste Vorsitzende Samuel Krutzky das Jahre revue passieren und bedankte sich bei allen, die, ob bei einem der Infostände, den Standschauen oder als Vermehrer von Reinzuchtköniginnen, das Vereinsleben bereicherten und den Verein unterstützten. Er wünschte allen anwesenden Imkerinnen und Imkern eine schöne und besinnliche Weihnachtszeit und ein erfolgreiches Bienenjahr in 2025.</div>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('praxis-bei-imkerversammlung-im-fokus', 'Praxis bei Imkerversammlung im Fokus', '2024-07-22', NULL, 'news/2024/7dffef58251d51f0.jpg', '<div>Bei sommerlichem Wetter hielten die Imker des Bienenzuchtvereins Grünberg ihre Monatsversammlung ausnahmsweise nicht in der Bildungsstätte Gartenbau, sondern kurzfristig im Freien ab. Anfang Juli wurde umgeplant und die Versammlung als Standschau auf dem Bienenstand des zweiten Vorsitzenden des Vereins, Ferdi Diedam, in Reinhardshain ausgerichtet. Diese tolle Gelegenheit nutzte Imkerberater Werner Bugdahl, um direkt nach der Begrüßung durch den ersten Vorsitzenden, Samuel Krutzky, an einem Bienenstock das „Bannwabenverfahren“ zur Varroabekämpfung zu demonstrieren. Bereits einige Tage zuvor hatte er eine leere Wabe mit der Königin des Bienenvolks in ein Käfigkonstrukt verschlossen und wieder in den Stock gehängt. Auf diese Weise kann die Königin nur dort ihre Eier legen, welche sich dann weiter zu Bienen entwickeln. Die Bienenbrut auf den anderen Waben wird von den Ammenbienen weiter versorgt und nach 21 Tagen schlüpfen, doch auf diesen Waben kann, da die Königin eingesperrt ist, keine neue Bienenbrut heranwachsen.&nbsp;<br>Wozu das Ganze? Imkerberater Bugdahl erklärte, dass die Varroamilbe sich in der Bienenbrut vermehrt. Durch die Bannwabe kann die Milbe sich jedoch irgendwann nur noch auf einer Wabe vermehren. Entnimmt man diese dann, ist der Vermehrungsrhythmus der Varroamilbe gestört und wiederholt man diese Prozedur mehrmals, stellt sie eine gute Alternative zu organischen Säuren dar, die dann nur noch in Ausnahmefällen angewendet werden müssen.&nbsp;<br>Alle Abläufe wurden dann zum besseren Verständnis an dem zuvor präparierten Anschauungsvolk durchgeführt.Bei dem anschließenden gemütlichen Beisammensein berichtete Schriftführer Karl Trüller von dem Informationsstand anlässlich des Tages der deutschen Imkerei, der in diesem Jahr auf dem Feierabendmarkt in Laubach zu finden war. In Kooperation mit Helge Euler, der netterweise einen Teil seines Standes für den Verein zur Verfügung stellte, konnten Daniela Weber, Lorenz Turbanisch und Karl Trüller den interessierten Marktbesuchern einige Interessante Dinge über die Imkerei und die Bienen erzählen. Der Blickfang und Publikumsmagnet war jedoch eindeutig der Schaukasten, den Werner Bugdahl mit Bienen bestückte und zum Markt brachte. Durch eine Glasscheibe konnten dort die Bienen in ihrem emsigen Treiben beobachtet werden, was vor allem die kleinen Besucher faszinierte. So konnte Trüller für die Öffentlichkeitsarbeit an diesem Tag ein positives Fazit ziehen, waren doch einige interessante Gespräche über die Imkerei zustande gekommen.&nbsp;</div>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('afb-sperrbezirk-bei-lich-wird-am-28-maerz-aufgehoben', 'AFB Sperrbezirk bei Lich wird am 28. März aufgehoben', '2024-03-26', NULL, 'news/2026/pxb-2540893-395f63ea.jpg', '<div>Nachuntersuchungen der betroffenen Bienenvölker waren negativ</div><div>Das Veterinäramt des Landkreises Gießen hebt den Sperrbezirk zum Schutz vor der Amerikanischen Faulbrut (AFB) bei Bienen im Bereich Lich auf. Damit entfallen ab Donnerstag, 28. März 2024, die bisher geltenden Beschränkungen für Imkereien im betroffenen Gebiet.</div><div>Der Sperrbezirk war im vergangenen Sommer nach der Feststellung der Seuche eingerichtet worden. Nach der groß angelegten Sanierungsaktion der befallenen Bienenvölker im September haben nun Nachuntersuchungen und Probenauswertungen im Landesbetrieb Hessisches Landeslabor keine Hinweise mehr auf die Erreger der AFB ergeben. Aus diesem Grund erlässt das Veterinäramt eine <a href=\"https://www.lkgi.de/wp-content/uploads/2024/03/Allgemeinverfuegung-–-Aufhebung-der-AFB-Sperrbezirke-26.03.2024.pdf\">Aufhebungsverfügung</a>.</div><div>Vorsorglich werden in den kommenden Wochen weitere Bienenvölker im betreffenden Gebiet untersucht, um eine verdeckte Verschleppung der AFB auszuschließen. Bienensachverständige entnehmen dafür Futterkranzproben im Rahmen eines Monitorings. Die betreffenden Imkereien werden direkt vom Veterinäramt kontaktiert. Sollten erneut Erreger nachgewiesen werden, wird das Veterinäramt die Situation bewerten und über mögliche Schritte informieren. Priorität hatte nun aber die Aufhebung des Sperrbezirks aus dem vergangenen Jahr, denn die Einschränkungen sollten nur solange bestehen wie unbedingt nötig.</div><div>„Ein großes Dankeschön geht an alle Helferinnen und Helfer aus den Imkervereinen, vor allem an die ehrenamtlichen Bienensachverständigen, die seit dem Ausbruch das Veterinäramt tatkräftig bei der Sanierung und Probenentnahme im Sperrbezirk unterstützt haben“, sagt Hauptamtlicher Kreisbeigeordneter Christian Zuckermann, zuständiger Dezernent des Landkreises.</div><div><strong>Grundsätzlich die Bienen vor AFB schützen</strong></div><div>AFB ist eine für Bienen hochansteckende Seuche, die zum Zusammenbruch und Tod ganzer Völker führen kann. Sie ist für Menschen nicht gefährlich.</div><div>Wer Bienen hält, ist durch die Bienenseuchenverordnung grundsätzlich zu Vorkehrungen zum Schutz vor der AFB verpflichtet, daran erinnert das Veterinäramt: Insbesondere dürfen Waben niemals offen und für andere Bienen zugänglich gelagert werden, dasselbe gilt für leere Bienenbehausungen. Wer sich Bienen anschafft, muss dies immer dem Veterinäramt anzeigen.</div><div>Niemals sollten Honig anderer Imkereien oder Honig aus dem Supermarkt an Bienen verfüttert werden, denn gerade Importhonig kann Faulbrutsporen enthalten.</div><div>Das Veterinäramt erinnert auch daran: Soll ein Bienenvolk über die Kreisgrenze gebracht werden, ist immer ein Gesundheitszeugnis zur Vorlage beim Veterinäramt am Zielort erforderlich. Auch innerhalb des Landkreises wird eine Abgabe von Bienenvölkern nur mit gültigem Gesundheitszeugnis empfohlen. Dazu kann das Veterinäramt erreicht werden unter Telefon (0641) 9390-6220 oder per E-Mail an <a href=\"mailto:poststelle.avv@lkgi.de\">poststelle.avv@lkgi.de</a>.</div><div>Weitere Informationen unter gibt es auf der Seite <a href=\"https://www.lkgi.de/aktuelle-tierkrankheiten/\">Aktuelle Tierkrankheiten</a>.</div>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('neue-honigkurse', 'Neue Honigkurse', '2023-10-05', NULL, NULL, '<p>Sehr geehrte Damen und Herren,</p>\n<p> </p>\n<p>wir bieten in diesem Herbst noch 5 Honigkurse an.</p>\n<p>Nähere Angaben zu den Terminen und Veranstaltungsorten finden Sie auf unserer Homepage unter folgendem Link: <a href=\"https://hessische-imker.de/aus-und-fortbildung/kursangebot-des-lhi/honiglehrgang/\">https://hessische-imker.de/aus-und-fortbildung/kursangebot-des-lhi/honiglehrgang/</a></p>\n<p>Die Anmeldung zu diesen Kursen kann ab 06.10.2023 in dem Anmeldeportal auf der Homepage erfolgen.</p>\n<p> </p>\n<p>Eine Anmeldung zu allen Kursen für 2024 ist ab dem 01.11.2023 ebenfalls auf unserer Homepage möglich.</p>\n<p> </p>\n<p>Mit freundlichen Grüßen</p>\n<p> </p>\n<p>LANDESVERBAND HESSISCHER IMKER E.V.</p>\n<p>-Geschäftsstelle-</p>\n<p>Erlenstraße 11</p>\n<p>35274 Kirchhain</p>\n<p>Tel.: 06422-2624</p>\n<p>Fax.: 06422-85356</p>\n<p>Homepage: <a href=\"http://www.hessische-imker.de/\">www.hessische-imker.de</a></p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('haltbarkeit-von-oxalsaeuredihydrat-loesung', 'Haltbarkeit von Oxalsäuredihydrat-Lösung', '2022-11-29', NULL, NULL, '<p><strong>LAVES – Institut für Bienenkunde Celle</strong></p>\nDr. Otto Boecking\n<p>LAVES – Institut für Bienenkunde Celle · Herzogin-Eleonore-Allee 5 · 29221 Celle</p>\n<p>Immer wieder aufkommende Fragen, ob Oxalsäure zur Bekämpfung der Varroa-Milbe nach dem Ablauf des Mindesthaltbarkeitsdatums schlecht wird, woran man das erkennt und ob man sie dann noch verwenden kann, zeigen, dass hier Informationsbedarf in der Imkerschaft besteht.</p>\nFür Arzneimittel gilt das Verfall(s)datum\n<p>Oxalsäure ist ein in Deutschland zugelassenes Arzneimittel (Akarizid) zur Bekämpfung der Varroa- Milbe (<em>Varroa destructor</em>). Hier gilt keine Mindesthaltbarkeit (MHD), die sich als vorgeschriebenes Kennzeichnungselement allein auf Lebensmittel beschränkt, sondern das Verfall(s)datum.</p>\n<p>Die sogenannte Standardzulassung1 zur Oxalsäuredihydrat-Lösung 3,5 % ad us. vet. zur Bekämpfung der Varroa-Milbe gibt genaue Vorgaben zur Herstellung, zur Verpackung und Anwenderangaben etc. an. Diese schreibt auch vor, dass ein Verfalldatum (einschließlich der notwendigen Lagerungsbedingungen) auf der Verpackung dieses Arzneimittels angegeben werden muss. Dies ist unverschlüsselt, zumindest in Jahr und Monat, anzuführen und die Worte „<em>Verwendbar bis</em>“ oder „<em>Verw. bis</em>“ voranzustellen. Rechtsgrundlage dazu bilden in Deutschland das Medizinproduktegesetz (MPG), das Arzneimittelgesetz (AMG) und nachgeordnete Rechtsvorschriften. Nach diesen Vorschriften ist das Tier-Arzneimittel „Oxalsäuredihydrat-Lösung 3,5 % ad us. vet.“ im unversehrten Behältnis ein Jahr haltbar. Arzneimittel und Medizinprodukte, die das Verfalldatum überschritten haben, dürfen nicht mehr in Verkehr gebracht bzw. angewendet werden.</p>\nZwischen der reinen (zuckerfreien) nicht gebrauchsfertigen und der gebrauchsfähigen, also angemischten Oxalsäuredihydrat-Lösung, muss unterschieden werden\n<p>Oxalsäure zur Bekämpfung der Varroa-Milbe wird in zwei Bestandteilen geliefert und ergibt erst nach Vermischung der Oxalsäuredihydrat-Lösung und dem Saccharose-Pulver eine gebrauchsfertige Lösung. Das gibt die Standardzulassung der Oxalsäuredihydrat-Lösung 3,5 % ad us. vet. vor. Also muss man zwischen der vom Imker fertig mit Zucker (Saccharose-Pulver) angerührten, gebrauchsfähigen Oxalsäuredihydrat-Lösung und der reinen (zuckerfreien), nicht gebrauchsfertigen Oxalsäuredihydrat-Lösung unterscheiden. Für die gebrauchsfertige Lösung gilt, wenn also das Saccharose-Pulver vom Imker untergemischt wurde, die sofortige Anwendung. Die Mischung sollte also möglichst nicht gelagert werden. Hier besteht nämlich bei unsachgemäßer warmer und längerer Lagerung die Gefahr, dass sich mittelfristig unter Einwirkung der Säure bienengefährliche Stoffe, wie ein hoher HMF-Gehalt, aus dem Zucker bilden. Zudem verfärbt sich aufgrund weiterer Abbauprodukte des Zuckers die Lösung dann bräunlich. Das haben Untersuchungen von Bogdanov und Kollegen (2001)2 aus der Schweiz gezeigt. Demnach stieg der HMF-Gehalt in der gebrauchsfertigen (zuckerhaltigen) Oxalsäuredihydrat-Lösung bei Lagerung unter Raumtemperaturen bereits nach wenigen Wochen stark an .</p>\n<p>Bekanntlich ist Hydroxymethylfurfural (HMF) toxisch für die Bienen. Wird hingegen die fertige Lösung bei 4 °C oder tiefer, also im Kühlschrank au fbewahrt, kann man fertig mit Zucker angerührte Oxalsäuredihydrat-Lösung durchaus ein paar Wochen im Kühlschrank vor der Anwendung aufbewahren. Dazu muss es aber gar nicht erst kommen, wenn man seinen Bedarf zuvor abschätzt und entsprechend nur die Menge aufmischt, die zur Behandlung der eigenen Bienenvölker benötigt wird. Oxalsäure zur Bekämpfung der Varroa-Milbe wird in zwei Bestandteilen geliefert und ergibt eine gebrauchsfertige Lösung von 500 ml. Eine solche Packung reicht also für ca. 10 bis 15 Behandlungen. Wenn man nur wenige Völker besitzt und die gebrauchsfertige Oxalsäuredihydrat-Lösung nicht unbegrenzt lagerfähig ist, lohnt es sich eventuell die Packung mit anderen Imkern zu teilen.</p>\nFür die Anwendung der Oxalsäure als Varroazid gilt\n<p>Wie oben ausgeführt, geben das Arzneimittel- und das Medizinproduktegesetz für die Anwendung der Oxalsäuredihydrat-Lösung 3,5 % ad us. vet. keinerlei Spielraum, der über die Gebrauchs- information, also das angegebene Verfalldatum hinausgeht. Für die gebrauchsfertige, mit Zucker aufgemischte Oxalsäuredihydrat-Lösung gilt die (möglichst) sofortige Verwendung.</p>\n<p>1 siehe: Bundesgesetzblatt Jahrgang 2006 Teil I Nr. 48, ausgegeben zu Bonn am 26. Oktober 2006, Zul.-Nr.: 2669.99.99</p>\n<p>2 Bogdanov S., Kilchenmann V., Charrière JD., Imdorf A. (2001) Lagerfähigkeit von Oxalsäure- Zuckerwasserlösungen Schweizerische Bienen-Zeitung. 2001(9): 21-22</p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('honigpraemierung-2022', 'Honigprämierung 2022', '2022-06-23', NULL, NULL, '<p>Auch dies Jahr findet wieder eine Honigprämierung statt.</p>\n<p>Für die Bedingungen und nötige Schritte zur Teilnahme bitte den unten angegebenen LINK anklicken.</p>\n<p>Unser Frank Schmied wird wieder als Koordinator die Daten für die Liste und dann die Honiglose für die Prämierung sammeln und für uns eine Fahrt nach Kirchhain unternehmen, damit die Lose pünktlich dort ankommen. DANKE dafür !!</p>\n<p>Für nähere Infos bitte Kontakt mit ihm aufnehmen. </p>\n<p> </p>\n<p>Hier der LINK:</p>\n<p><a href=\"https://hessische-imker.de/page/termine/hessische-honigpraemierung-2022/\">https://hessische-imker.de/page/termine/hessische-honigpraemierung-2022/</a></p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('citizen-science-versuch-2022-varroadiagnose-optimieren', 'CITIZEN SCIENCE-VERSUCH 2022 „VARROADIAGNOSE OPTIMIEREN\"', '2022-06-20', NULL, NULL, '<p>Das Bieneninstitut Kirchhain möchte Sie im Rahmen des EIP-Projekts „Praxis-Forschung-Bienen\" einladen an einem gemeinsamen, hessenweiten Versuch teilzunehmen. Einige von Ihnen konnten wir das Projekt bei den lmkerberater-Schulungen im Mai bereits persönlich vorstellen, Sie finden unten wie besprochen den Link zur Anmeldemaske, die nun online ist und auf Ihre Registrierung wartet.</p>\n<p>Nachdem wir in den vergangenen beiden Jahren in diesem Projekt Feldversuche zum Thema Varroabehandlung und Diagnose durchgeführt haben, möchten wir in dieser Saison gemeinsam mit Ihnen Neuland betreten: Wir werde den ersten „Citizen Science\"-Versuch am Bieneninstitut Kirchhain durchführen, also einen Feldversuch, bei dem eine größere Zahl von Imkerinnen und Imkern Daten an ihren eigenen Bienenvölkern aufnimmt.</p>\n<p>Grundvoraussetzung für eine erfolgreiche Varrobehandlung ist, den richtigen Zeitpunkt für die Behandlung zu erkennen. Das geht nur, wenn der Milbenfall regelmäßig, einfach und sicher erfasst werden kann. Bei dem geplanten Citizen Science-Versuch geht es deshalb um die Diagnose des Varroabefalls von Bienenvölkern. Der Versuch besteht konkret darin, von Juli bis Oktober jeweils Anfang des Monats einen ungeölten und direkt danach einen geölten Bodenschieber für den Zeitraum von drei Tagen einzulegen und jeweils die Milben zu zählen und zu notieren.</p>\n<p>Wir laden Sie - als wichtige Multiplikatoren in den hessischen lmkervereinen - ein an dem Versuch teilzunehmen und sich selbst ein Urteil über die Methodik zu bilden. Dafür benötigen Sie nur Bienenvölker mit möglichst durchgängigem Gitterboden und dicht schließendem Bodenschieber, die restlichen Versuchsmaterialien werden Ihnen von uns kostenfrei zur Verfügung gestellt.</p>\n<p> </p>\n<p>Falls wir ihr Interesse geweckt haben, können sie sich ab sofort unter folgendem Link registrieren:</p>\n<p><a href=\"https://llh.hessen.de/citizen-science-versuch-2022/\"></a><a href=\"https://11h.hessen.de/citizen-science-versuch-2022/\">https://11h.hessen.de/citizen-science-versuch-2022/</a></p>\n<p>Nach der Anmeldung werden Ihnen die Versuchsmaterialien und detaillierte Informationen zur Versuchsdurchführung zugestellt.</p>\n<p>Falls sie sich vorstellen können, noch weitere Imkerinnen und Imker aus ihrem Verein für den Versuch begeistern zu können, leiten sie dieses Schreiben bitte weiter. Gerne organisieren wir dann eine gesammelte Übergabe der Versuchsmaterialien bei Ihnen vor Ort.</p>\n<p>Weiterhin eine schöne und erfolgreiche lmkersaison!</p>\n<p>Mit freundlichen Grüßen aus Kirchhain,</p>\n<p>i.A. Daniel Brechensbauer</p>\n<p>Erlenstraße 9<br/>35274 Kirchhain<br/>Tel: +49 6422 9406 19</p>\n<p> </p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('neues-tierarzneimittelgesetz-tritt-in-kraft', 'Neues Tierarzneimittelgesetz tritt in Kraft', '2022-02-25', NULL, NULL, '<h3><strong>Imkerinnen und Imker müssen Dokumentationspflicht beachten</strong></h3>\n<p>Im Zuge der Neuordnung des Gemeinschaftsrechts ist am 28.1.2022 die neue EU-Verordnung EU TAM VO 2019/6 europaweit in Kraft getreten. In Deutschland werden die Regelungen zur Tierarznei damit aus dem Arzneimittelgesetz herausgelöst und in das neue Tierarzneimittelgesetz (TAMG) überführt. Für Imkerinnen und Imker ändert sich dabei in der Arzneimittelgabe zunächst nichts, weil die Regelungen des TAMG weitgehend der bisherigen Rechtslage entsprechen.</p>\n<p>Zwei Hinweise sind dennoch zu beachten. Die EU-Verordnung schreibt Imkernden in Artikel 108 die Buchführung über die von ihnen verwendeten Arzneimittel explizit vor. Mit dem Inkrafttreten der Verordnung ist das auch in Deutschland unmittelbar geltendes Recht. Der Deutsche Imkerbund e.V. empfiehlt, alle Arzneimittelgaben in ein Bestandsbuch aufzunehmen – auch jene, die ein Tierarzt angeordnet hat. Bei einer Kontrolle sorge das für Klarheit. Das Bestandsbuch muss nicht unbedingt ein Buch sein, es kann sich auch um eine lose Blattsammlung handeln. Wichtig ist aber, dass diese Dokumentation fünf Jahre aufzubewahren ist.</p>\n<p>Ein weiterer wichtiger Punkt findet sich in § 106 der EU-Verordnung. Dort heißt es: „Tierarzneimittel werden in Übereinstimmung mit den Zulassungsbedingungen angewendet.“ Damit sind Behandlungsmethoden wie etwa die Ameisensäureeinbringung mit dem Schwammtuch verboten. Diese weit verbreitete Schock-Behandlung ist in der Zulassung von Ameisensäure nicht beschrieben und damit nicht zulässig. „Die EU wollte durch diese Formulierung wohl privaten Experimenten einen Riegel vorschieben und hat damit aber leider auch den Einsatz des Schwammtuchs verboten“, sagt Dr. Michael Hardt, der im D.I.B.-Präsidium für Bienengesundheit zuständig ist.</p>\n<p>Quelle: <a href=\"https://deutscherimkerbund.de/534-TAMG\">https://deutscherimkerbund.de/534-TAMG</a></p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('hilfe-fuer-die-flutopfer-im-ahrtal', 'Hilfe für die Flutopfer im Ahrtal', '2022-01-12', NULL, NULL, '<p><strong>Rundschreiben Nr.: 1/2022 vom Landesverband Hessischer Imker e.V.</strong></p>\n<p> </p>\n<p>Hilfe für die Flutopfer im Ahrtal<br/>Liebe Kreisvereinsvorsitzende und Vereinsvorsitzende, liebe Imkerfreunde,<br/>vergangenes Jahr hat das Ahrtal eine Flutkatastrophe in bisher noch nicht dagewesenem Ausmaß getroffen. Die zahlreichen Schäden schließen auch Imker und ihre Bienen mit ein. Völker und Beuten fielen dem Wasser zum Opfer, Gerätschaften und Zubehör befanden sich in überfluteten Häusern.<br/>Der Landesverband Hessischer Imker möchte in Zusammenarbeit mit dem DIB und anderen Landesverbänden Hilfe für die betroffenen Imker organisieren. Wenn die kommende Bienen-Saison startet, werden Lebendmaterial (Völker oder Ableger) sowie Sachspenden gebraucht. Ihre Spenden sollen es den hochwassergeschädigten Imkern ermöglichen im kommenden Frühling ihr imkerliches Hobby, ihren Nebenerwerb und die unentgeltliche Bestäubungsleistung für Bevölkerung und Landwirtschaft wiederaufzunehmen.<br/>Um die Spenden besser organisieren und später verteilen zu können, sollen diese an einem zentralen Ort gesammelt, von dort abgeholt und ins Ahrtal gebracht werden. Für den Transport werden wir uns mit anderen Landesverbänden zusammenschließen, damit wir diesen möglichst effizient gestalten können. Um die notwendige Transportkapazität abschätzen zu können, möchten wir Ihre Rückmeldung erbitten, was Sie spenden möchten und welcher Platzbedarf (m³) in einem Transporter benötigt wird. (Alternativ melden Sie uns bitte Höhe, Länge und Breite der Spenden.) Lebendmaterial werden wir in Absprache mit dem Imkerverband Rheinland organisieren/verteilen. Bitte beachten Sie, dass für die Spende von Völkern/Ablegern unbedingt ein aktuelles Gesundheitszeugnis erforderlich ist! Bitte nutzen Sie die dem Rundschreiben beigefügte Excel-Tabelle für Ihre Rückmeldungen und senden Sie uns diese bis zum 15.02.2022 per Mail zu.<br/>Sollten Sie eine Geldspende tätigen wollen, richten Sie diese bitte direkt an den Imkerverband Rheinland, da dieser Ihnen auf Wunsch eine Spendenquittung ausstellen kann. Nähere Informationen zu Geldspenden finden Sie online unter: <a href=\"https://imkerverbandrheinland.de/2021/08/imker-helfen-imkern/\">https://imkerverbandrheinland.de/2021/08/imker-helfen-imkern/</a> .<br/>Wir danken Ihnen für Ihre Unterstützung und Solidarität in Notzeiten.<br/>Mit freundlichen Grüßen<br/>gez. Manfred Ritz<br/><br/></p>\n<p><a href=\"https://www.bienenzuchtverein-gruenberg.de/images/saatgut_2022/Fragebogen-Imkerhilfe.xlsx\">Die Tabelle kann hier heuntertgeladen werden</a></p>\n<p> </p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('biodiversitaet-bluehflaechensaatgut', 'Biodiversität - Blühflächensaatgut', '2022-01-12', NULL, NULL, '<p>Der Hessische Bauernverband bietet wieder einjähriges Saatgut, geeignet für Ackerrandstreifen und auch für die Greeningflächen oder Bienenbrachen an.</p>\n<p>Das Saatgut ist in 10 kg Packungen abgepackt. Beachten Sie die Bestellfristen für konventionelles (14.01.2022, 12 Uhr) und ökologisches (21.01.2022, 12 Uhr) Saatgut!.</p>\n<p><a href=\"https://www.bienenzuchtverein-gruenberg.de/images/saatgut_2022/RS-02-22.pdf\">Das Rundschreiben kann hier heruntergeladen werden.</a></p>\n<p><a href=\"https://www.bienenzuchtverein-gruenberg.de/images/saatgut_2022/Angebot_HBV_04.01.22.pdf\">Informationen zur Bestellung findet Ihr hier.</a></p>\n<p> </p>\n<p> </p>\n<p> </p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('gruenberger-honige-fuer-hoechste-qualitaet-ausgezeichnet', 'Grünberger Honige für höchste Qualität ausgezeichnet', '2021-11-30', NULL, '/bilder/news/2021/gruenberger-honige-fuer-hoechste-qualitaet-ausgezeichnet.jpg', '<p></p>\n<p> </p>\n<p>Einmal im Jahr prämiert der Landesverband hessischer Imker (LHI) die besten Honige des Landes beim hessischen Honigtag. Der schöne Ort Bad Sooden-Allendorf im Werra-Meißner-Kreis diente hierzu in diesem Jahr als Gastgeber. Nachdem die Besucher Dr. Thomas Goglers Ausführungen zu dem interessanten Thema „Jenseits von Honig – Schätze aus dem Bienenvolk“ gelauscht hatten, konnte zur Tat geschritten werden – es wurden die Urkunden für die besten Honige Hessens überreicht! Zur Honigprüfung wurden von den Imkern 63 Honige eingereicht, die stellvertretend für Honig von Imkern aus dem ganzen Land stehen. Schon bei der Anzahl konnte der Bienenzuchtverein Grünberg und Umgebung e.V. besonders glänzen, stammt doch mit 16 Honiglosen ein beachtlicher Teil der eingereichten Honige aus dem Verein. Auch in der Bewertung schnitten die mittelhessischen Bienenzüchter sehr gut ab. Insgesamt wurden 48 Honigproben durch den LHI ausgezeichnet, 13 davon allein von Vereinsmitgliedern des Bienenzuchtvereins Grünberg. So konnten die Honige von Samuel Krutzky und Annemarie Sauerbier mit einer Bronzemedaille, sowie die Honige von Barbara Gümbel, Susanne Nachtigall, Frank Schmied und Tobias Schmitt mit einer Silbermedaille ausgezeichnet werden. Des Weiteren wurden durch den LHI-Vorsitzenden Manfred Ritz die Honige von Holger Kühn, Wolfram Meerbott, Anja Schnecko, Dirk Münster und Werner Bugdahl auf dem Honigtag mit der Goldmedaille prämiert. Im Anschluss erhielten die besten der prämierten Honige eine besondere Auszeichnung. Der Imker Wolfram Meerbott wurde für sein Honiglos mit der Ehrenmedaille in Silber des Deutschen Imkerbundes (DIB) ausgezeichnet, sein Imkerkollege Werner Bugdahl konnte sich gar über die Ehrenmedaille in Gold des DIB freuen.</p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('notfallzulassung-fuer-bienentoxisches-neonico-tinoid-vorerst-vom-tisch', 'Notfallzulassung für bienentoxisches Neonicotinoid vorerst vom Tisch', '2021-11-30', NULL, NULL, '<p>Wachtberg, 25.11.2021: „Ein Problem, das wir bereits Ende letzten Jahres hat-ten, ist erneut aufgetreten - nur mit bisher besserem Ausgang“, sagte D.I.B.-Präsident Torsten Ellmann vor wenigen Tagen. Gemeint ist damit die Notfallzu-lassung für den Wirkstoff Thiamethoxam, den die Wirtschaftliche Vereinigung Zucker e.V. beim Bundesamt für Verbraucherschutz und Lebensmittelsicherheit (BVL) im Herbst beantragt hat. Begründung: Blattläuse bei Zuckerrüben als Vi-rusüberträger systemisch zu bekämpfen und dabei den Wirkstoff Thiametho-xam prophylaktisch regional einzusetzen.<br/>„Dieser Ansatz entspricht nicht unserer Grundsatzforderung, auf den Einsatz von Neonicotinoiden im Pflanzenbau zu verzichten“, so Ellmann. „Wir haben aus diesem Anlass unverzüglich unsere fachversierte Position gegenüber dem zu-ständigen Bundesministerium für Landwirtschaft und Ernährung als auch seiner zuständigen Durchführungsbehörde (BVL) mitgeteilt. Eine neuerliche lokale flä-chendeckende, prophylaktische Notfallzulassung aufgrund möglicherweise zu erwartender Behandlungsnotstände lehnen wir mit guten Gründen kategorisch ab.“<br/>Unsere dargelegten Begründungen lesen Sie im Folgenden:<br/>• Aus Sicht des D.I.B. wurde sich eine viel zu lange Zeit auf die Pflanzen-schutzmittel-Industrie verlassen und es längst versäumt, maßgebliche Zuchtziele auch im Hinblick auf natürliche Resistenz-Eigenschaften der Kulturpflanzen zu definieren. Das Dilemma im Zuckerrübenanbau auf-grund virusübertragender Blattläuse im Jugendstadium der Zuckerrübe ist bereits seit den 1980er Jahren bekannt. Europäische Resistenzzüch-tungen der 1980/1990er Jahre wurden unserer Meinung nach lange vernachlässigt, da die neuen Behandlungsmethoden wirtschaftliche Vor-teile versprachen und die Züchter keinen Anreiz sahen.<br/>• Auch wenn die Wirkstoffmengen zur Notfallzulassung so stark reduziert sind, dass die jungen, besonders anfälligen Pflänzchen über die Saat-gutpille systemisch ausreichend geschützt sind, kann eine abermalige Notfallzulassung eines verbotenen Neonicotinoids nicht toleriert wer-den. Insbesondere deshalb nicht, weil dieser prophylaktische Einsatz nicht den Anforderungen an den Integrierten Pflanzenbau entspricht, der sich nach dem Schadschwellen-Prinzip zu richten hat.<br/>• Die mit der Notfallzulassung 2021 verbundene Auflage, nach der Ro-dung und im Folgejahr keine Blühpflanzen auf diesen Äckern zu bestel-len, macht das bodenbürtige Risiko für Bestäuber, insbesondere im Bo-den nistende Wildbienen, deutlich.<br/>• Zudem würde mit der Einschränkung von Blühstreifen oder Flächenstill-legungen durch die Notfallzulassung das bereits schon sehr knappe Nahrungsangebot für alle Blüten besuchenden Insekten nachhaltig wei-ter drastisch reduziert.<br/>• Auch das Problem des Auswaschens gefährlicher Wirkstoffe und Pfützen-<br/>bildung birgt, wie in diesem Jahr geschehen, ein lebensgefährliches Risi-<br/>ko für Bestäuber.<br/>Seite 2 von 2<br/>„Außerdem kritisieren wir die fehlende, erforderliche Transparenz, die mit der unterschiedlichen Umsetzung der Notfallzulassung und individuellen Regelungen in den jeweiligen Bundesländern nicht gegeben ist“, betont Torsten Ellmann.<br/>Dem Deutschen Imkerbund e.V. ist durchaus bewusst, das mit dem Verbot relevanter Neonicotino-ide Pflanzenanbauer sowie aus aktuellem Grund insbesondere der europäische Zuckerrübenanbau in einigen Regionen ein elementares Problem haben. Ausnahmegenehmigungen ohne jegliche Per-spektiven stellen aber keine grundsätzliche Lösung des Problems dar.<br/>Der derzeitige Sachstand laut BVL ist, dass es keine Notfallzulassung für das Frühjahr 2022 geben wird.<br/>Zugleich hat der D.I.B. beiden Institutionen sowie den Zuckeranbauverbänden erneut vorgeschla-gen, gemeinsam insektenfreundliche, alternative Anbaukonzepte zu begleiten.<br/>Hintergrund: Am 13.12.2020 wurde durch das BVL auf Grundlage der EU-Pflanzenschutzmittelverordnung die Notfallzulassung für den Wirkstoff, geltend vom 01.01. - 30.04.2021, erteilt. Vorausgegangen waren Anträge von sieben Bundesländern, basierend auf der Begründung, nur so große Schäden im Rübenanbau abwehren zu können.<br/>Wie das BVL damals erläuterte, führe das Vergilbungsvirus zu gravierenden Pflanzenschäden und Ertragsverlus-ten. Die Notfallzulassung sei daher aus pflanzenepidemiologischer Sicht zur Eindämmung der weiteren Viren-ausbreitung bei Rüben wichtig. Bis 2018 war die Verwendung des Wirkstoffes bei Zuckerrübensaatgut zulässig.<br/>Die Zulassung umfasste die Beizung von Zuckerrübensaatgut mit dem Pflanzenschutzmittel Cruiser 600 FS, welches als Wirkstoff das hochwirksame Neonicotinoid Thiamethoxam enthält. Die betreffenden Bundesländer verpflichteten sich mit der Notfallzulassung, alle erforderlichen Maßnahmen zu ergreifen, um sicherzustellen, dass mit Cruiser 600 FS behandeltes Saatgut auf den benannten Flächen fachgerecht eingesetzt wird. Dabei waren genaue Auflagen und Überwachungsinstrumente in den einzelnen Bundesländern unterschiedlich geregelt und unter anderem ein Anbau blühender Pflanzen im Folgejahr untersagt.<br/>Lesen Sie dazu unsere Mitteilung in D.I.B. AKTUELL 1/2021 unter <a href=\"https://deutscherimkerbund.de/userfi-les/DIB_Aktuell/2021/aktuell2021-1.pdf.\">https://deutscherimkerbund.de/userfi-les/DIB_Aktuell/2021/aktuell2021-1.pdf.</a><br/>Unsere Position zum Einsatz von Pflanzenschutzmitteln finden Sie unter <a href=\"https://deutscherimker-bund.de/157-Unsere_Positionen.\">https://deutscherimker-bund.de/157-Unsere_Positionen.</a><br/>Kontakt:<br/>Petra Friedrich, <a href=\"mailto:presse@imkerbund.de\">presse@imkerbund.de</a>, Tel. 0228/9329218 o. 0163/2732547</p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('newsletter-vom-bieneninstitut-kirchhain', 'Newsletter vom Bieneninstitut Kirchhain', '2021-11-02', NULL, NULL, '<p>Der Newsletter erscheint quartalsweise und bietet Ihnen Informationen und Hinweise zu unseren Projekten, Fachbeiträgen, Lehrgängen, Veranstaltungsterminen, Verkaufsangeboten und vieles mehr.</p>\n<p>Das ist der Link:  <a href=\"https://llh.hessen.de/newsletter-bieneninstitut/\"></a><a href=\"https://llh.hessen.de/newsletter-bieneninstitut/\">https://llh.hessen.de/newsletter-bieneninstitut/</a></p>\n<p> </p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('magere-fruehjahrsernte-in-den-meisten-landesteilen', 'Magere Frühjahrsernte in den meisten Landesteilen', '2021-08-06', NULL, NULL, '<p><a href=\"https://deutscherimkerbund.de/userfiles/DIB_Pressedienst_Oeffentlichkeitsarbeit/Pressemitteilung/Fruehjahrsernte_mager_05_08_2021Endfassung.pdf\">Pressemitteilung des DEUTSCHERIMKERBUND E.V.</a></p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('bienenkrankheiten-gesucht', 'Bienenkrankheiten gesucht!', '2021-06-09', NULL, NULL, '<p>Für die Produktion von Lehrfilmen im Rahmen des Projekts „Praxis Forschung<br/>Bienen“ sind wir auf der Suche nach Symptomen von Bienenkrankheiten, die wir<br/>filmen und fotografieren dürfen.<br/>Wir suchen speziell nach dem Auftreten von:<br/> </p>\n<ul>\n<li>Sackbrutvirus</li>\n<li> Kalkbrut</li>\n<li> Deformed Wing Virus</li>\n<li> Chronisches Bienen Paralyse Virus</li>\n<li> Durchfallerscheinungen Außerdem Schädlinge der Honigbiene wie z.B. Asiatische Hornisse vespa velutina, Wachsmotte und Bienenlaus</li>\n<li> Sämtliche meldepflichtigen Bienenkrankheiten (AFB, EFB, Tropilaelaps Milbe, kleiner Beutenkäfer)</li>\n</ul>\n<p><br/>Natürlich behandeln wir ihre Meldungen vertraulich!<br/>Gerne besuchen wir sie auf dem betroffenen Bienenstand und geben ihnen bei der Gelegenheit auch Tipps, wie sie ihre Völker wieder kurieren können.<br/>Kontakt:<br/>Bieneninstitut Kirchhain, D.Brechensbauer<br/>Tel.: 06422-940619, <a href=\"mailto:daniel.brechensbauer@llh.hessen.de\">daniel.brechensbauer@llh.hessen.de</a></p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('informationen-zum-foerderprogramm-oeko-bienenhaltung', 'Informationen zum Förderprogramm „Öko-Bienenhaltung“', '2021-05-06', NULL, NULL, '<p>Der Landesverband Hessischer Imker e.V. informiert hier  über ein Förderprogramm zur Öko-Bienenhaltung.</p>\n<p> </p>\n<p><a href=\"https://www.bienenzuchtverein-gruenberg.de/images/foerderprogramm/RS-07-21.pdf\">Anschreiben</a></p>\n<p><a href=\"https://www.bienenzuchtverein-gruenberg.de/images/foerderprogramm/Merkblatt_Umstellungsprämie.pdf\">Merkblatt</a></p>\n<p><a href=\"https://www.bienenzuchtverein-gruenberg.de/images/foerderprogramm/Anlage_3_Merkblatt_Datenschutz.pdf\">Anlage Merkblatt</a></p>\n<p><a href=\"https://www.bienenzuchtverein-gruenberg.de/images/foerderprogramm/Antrag_Umstellungsprämie_final_2021-04-29.pdf\">Antrag Umstellungsprämie</a></p>\n<p><a href=\"https://www.bienenzuchtverein-gruenberg.de/images/foerderprogramm/Anlage_1_Bankverifizierung_Umstellungsprämie.pdf\">Anlage Bankverifizierung_Umstellungsprämie</a></p>\n<p> </p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('pressemitteilung-des-deutscherimkerbund-e-v', 'Pressemitteilung des DIB', '2021-03-25', NULL, NULL, '<p><a href=\"https://deutscherimkerbund.de/userfiles/DIB_Pressedienst_Oeffentlichkeitsarbeit/pdf/ots_Acetamiprid_23_03_21.pdf\">Hier finden Sie die aktuelle Pressemitteilung </a></p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('standschau-16-5-2020-geschuezter-bereich', 'Standschau 16.5.2020', '2020-05-21', NULL, NULL, '<p>Am 16.05.2020 fand wieder eine Standschau diesmal bei Susanne Weissbecker in Lauter statt.</p>\n<p>Die Standschau begann um 15:00 Uhr. 19 Mitglieder haben sich eingefunden. Das Thema war diesmal Schwarmverhinderung durch Zwischenbodenableger. Robert hat referiert und praktisch mit einer Magazinbeute demonstriert.</p>\n<p>Es wurde theoretisch und praktisch die Vorgehensweise erklärt und demonstriert.</p>\n<p>Mitglieder haben die Möglichkeit nach der <a href=\"https://www.bienenzuchtverein-gruenberg.de/index.php/anmelden\">Anmeldung</a> auf dieser Seite ein Video vom Vortrag anzusehen.</p>\n<p><a href=\"https://www.bienenzuchtverein-gruenberg.de/index.php/aktuelles/2-uncategorised/133-video-standschau-16-05-2020\">Hier geht es zum Video</a></p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('honigpraemierung-2020', 'Honigprämierung 2019', '2019-11-15', NULL, '/bilder/news/2019/honigpraemierung-2020.jpg', '<p>Das Jahr 2019 war für die Honigernte sehr schwierig. Frühtracht gab es nur wenig, für manchen unter uns sogar nichts. Im Sommer sah es dann besser aus. Der eine oder andere durfte seine Honigtöpfe doch recht gut füllen. Erfreulicherweise war dieser Honig von erstklassiger Qualität.</p>\n<p>Das haben wir dann auch bei der Honigprämierung gemerkt.</p>\n<p>Zwei unserer Imker haben Bestpreise für ihre hervorragenden Honige erzielt:</p>\n<p>Frank Schmied erhielt die Ehrenplakette des Landes Hessen in Silber;</p>\n<p>Stefan Böck durfte sich über die Ehrenmedaille des DIB ebenfalls in Silber freuen.</p>\n<p>Herzlichen Glückwunsch !</p>\n<p>Auch andere bekamen Auszeichnungen:</p>\n<p>Werner Bugdahl Gold, Samuel Krutzky Gold, Susanne Nachtigall Silber, Susanne Weißbecker Silber, Wolfram Meerbott Bronze.</p>\n<p></p>\n<p>Wir Grünberger Imker freuen uns, so erfolgreiche Kollegen beglückwünschen zu dürfen.</p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('asiatischen-hornisse', 'Asiatische Hornisse', '2019-10-29', NULL, NULL, '<h2><strong>Pressemitteilung</strong></h2>\n<p> </p>\n<p><strong>Erster Nachweis der Asiatischen Hornisse in Hessen</strong><br/>HLNUG bittet darum, Sichtungen zu melden<br/>Wiesbaden, 21.10.2019 - Durch Belegfotos eines Imkers aus Lorsch konnte zum ersten Mal die Asiatische Hornisse in Hessen nachgewiesen werden. Damit findet eine weitere, bisher in Hessen nicht vorkommende Art ausreichende Lebensbedingungen vor, um hier Populationen<br/>zu gründen.<br/>Die Asiatische Hornisse steht auf der Unionsliste der invasiven gebietsfremden Arten, gehört also zu dem kleinen Teil von neuen Arten in Hessen, die heimische Arten in ihrem Bestand gefährden können. Im konkreten Fall gibt es Berichte, dass sie eine Gefährdung der einheimischen Wespen- und Bienenarten darstellen kann. Um dies zu prüfen, werden Daten benötigt, wo und wie schnell sich das Insekt in Hessen ausbreitet.<br/>Das für das Monitoring invasiver Arten zuständige Hessische Landesamt für Naturschutz,Umwelt und Geologie (HLNUG) hat deshalb ein Meldeportal eingerichtet. Dort können Bürgerinnen und Bürger ohne Registrierung oder Anmeldung eine Fundmeldung weitergeben und damit dazu beitragen, die Datenlage zur Asiatischen Hornisse zu verbessern. Das HLNUG wertet die Meldungen aus und speichert sie in der hessischen Biodiversitätsdatenbank. Auf der Meldeseite gibt es auch zahlreiche weitere Informationen zur Asiatischen Hornisse wie zum Beispiel dazu, wie sie sich von der europäischen Hornisse unterscheidet.</p>\n<p>Webadresse, um Sichtungen der Asiatischen Hornisse zu melden: <a href=\"https://www.hlnug.de/themen/naturschutz/tiere-und-pflanzen/arten-melden/hornisse.html\">https://www.hlnug.de/themen/naturschutz/tiere-und-pflanzen/arten-melden/hornisse.html</a><br/>Pressesprecher Helmut Weinberger<br/>Hessisches Landesamt für Naturschutz, Umwelt und Geologie<br/>Rheingaustraße 186<br/>D-65203 Wiesbaden<br/>0611 - 6939 571<br/><a href=\"mailto:helmut.weinberger@hlnug.hessen.de\">helmut.weinberger@hlnug.hessen.de</a></p>', 1);
