INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('vorbereitung-von-honigglaesern-fuer-honigpraemierung', 'Vorbereitung von Honiggläsern für Honigprämierung', '2019-08-06', NULL, '/bilder/news/2019/vorbereitung-von-honigglaesern-fuer-honigpraemierung.jpg', '<p>Unser ehemaliger Imkerberater Stefan Böck ist immer noch fleißig für uns da:</p>\n<p>Am Montag, 15 Juli 2019, nahm er sich die Zeit, interessierten Imkern die Vorbereitung von DIB-Gläsern zur Honigprämierung anschaulich zu erklären.</p>\n<p>Das Angebot wurde von einigen Imkern dankbar angenommen.</p>\n<p>Ein paar Honiggläser wurden genau unter die Lupe genommen und fachmännisch etikettiert.</p>\n<p>Dabei wurde natürlich auch ausgiebig über den richtigen Umgang mit dem wertvollen Produkt Bienenhonig gesprochen:</p>\n<p> </p>\n\n \n \n\n \n ', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('honigpaemierung-2019', 'Honigprämierung 2019', '2019-05-21', NULL, NULL, '<h3>Hessische Honigprämierung 2019</h3>\n<p><br/><strong>Einladung zur Teilnahme</strong><br/>Der Landesverband Hessischer Imker lädt Sie auch im Jahr 2019 zur Honigprämierung herzlich ein. Wie schon in den Vorjahren wird die Prämierung im Spätsommer stattfinden.<br/>Die Honigprämierung trägt dazu bei, den hohen Qualitätsstandard unseres hessischen Honigs auch dem Kunden gegenüber unter Beweis zu stellen und somit auch in Zukunft zu erhalten. Die eingereichten Honige werden neben einer optisch-sensorischen Prüfung auch einer chemisch-physikalischen Analyse unterzogen. Die jeweiligen Proben/Honiglose werden auf Wassergehalt und Invertaseaktivität untersucht. Zudem wird jeweils ein Los des Teilnehmers auf chemische Rückstände (Varroabekämpfungsmittel und ausgewählte Pflanzenschutzmittel einschl. Neonikotinoiden) untersucht.<br/>Eine Teilnahme bietet also auch eine preisgünstige Möglichkeit, Ihren Honig im Labor untersuchen zu lassen. Eine Sortenanalyse erfolgt nicht.<br/>Die Teilnahme an der Honigprämierung bietet Ihnen die Möglichkeit, Ihren Honig und Ihr Können einer fachkundigen und neutralen Prüfung zu unterziehen. Gleichzeitig erhalten Sie dabei wertvolle Tipps und Hinweise um Ihr Wissen um das Thema Honigbearbeitung und Optimierung des Verkaufsgebindes im DIB-Glas zu vervollkommnen.</p>\n<p>Der Honig mus bis zum 8.8.1019 bei Werner Bugdahl oder bei Frank Schmied Tel.:015754323713 abgeliefer werden. Bis zum 2 August 2019 muss die Prüfungsgebühr 30Euro je Los auf das Konto IBAN DE72 5186 1403 0000 2519 09,BIC: GENODE51BUT überwiesen worden sein. </p>\n<p><strong><a href=\"https://www.bienenzuchtverein-gruenberg.de/images/Dokumente/Einladung_zur_Honigprämierung_2019_1.pdf\">Infopdf</a></strong></p>\n<p><strong><a href=\"https://www.bienenzuchtverein-gruenberg.de/images/Dokumente/Anmeldeformular_Honigpraemierung_2019_1.doc\">Anmeldeformular</a></strong></p>\n<p> </p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('weihnachstkaffe', 'Weihnachtskaffee 2018', '2019-01-06', NULL, '/bilder/news/2019/weihnachstkaffe.jpg', '<p> </p>\n<p></p>\n<p><strong>Ehrungen bei Adventscafe</strong><br/>Imker für ihre Honige und bis zu 70 Jahre Mitgliedschaft geehrt<br/>Der Bienenzuchtverein Grünberg hat sich auch dieses Jahr wieder zum Adventscafe getroffen. Eingangs bedankte sich der Vorsitzende, Samuel Krutzky, bei allen engagierten Imkern für ihren Einsatz. Anschließend blickten die Anwesenden bei Kaffee und Kuchen in gemütlicher Runde gemeinsam auf das vergangene Jahr zurück:<br/>Auch in diesem Jahr organisierte der Landesverband Hessischer Imker e.V. (LHI) wieder eine Honigprämierung, welche Mitte November in Gersfeld-Hettenhausen stattfand. Über 8000 Imkerinnen und Imker in den über 160 Ortsvereinen waren aufgerufen, Honige zur Prämierung einzureichen. Neben einer Rückstandsanalyse auf Pflanzenschutzmittel und andere chemische Stoffe werden hierbei die äußere Aufmachung des Honigs, die Reinheit, der sortentypische Geschmack und Geruch, der Gehalt an Invertase und der Wassergehalt bewertet.<br/>Die vergebenen Medaillen sprechen für die hohe Qualität des regionalen Honigs. Nach der Auswertung aller eingegangenen Honiglose freuten sich auch sechs heimische Imker des Bienenzuchtvereins Grünberg und Umgebung über Auszeichnungen.<br/>Goldmedaillen für ihre geernteten Honige erhielten Stefan Böck, Werner Bugdahl und Wolfram Meerbott. Mit Silbermedaillen für den Honig ihrer Bienen wurden Wolfram Meerbott, Anja Schnecko, Susanne Weißbecker sowie Frank Schmied ausgezeichnet.<br/>Mit dem Kauf des Honigs direkt vom Imker vor Ort unterstützt der Verbraucher nicht nur die heimische Bienenhaltung, sondern fördert auch die notwendige Bestäubung der Blütenpflanzen durch die Bienen.<br/>Weiterhin wurden am Adventscafe langjährige Mitglieder des Landesverbandes hessischer Imker (LHI) geehrt. An Kurt Lumbe wurde die Ehrennadel in Bronze für 15 Jahre Mitgliedschaft überreicht. Die Ehrennadel in Silber für 25 Jahre Mitgliedschaft erhielten Rudolf Dietzler, Udo Eckhardt und Holger Adler. Hans Herdt bekam für seine 40-jährige Mitgliedschaft im Landesverband hessischer Imker die Ehrennadel in Gold überreicht. Zum krönenden Abschluss wurde Ernst Maul aus Harbach eine besondere Ehrung für sage und schreibe 70 Jahre Mitgliedschaft im Landesverband von Samuel Krutzky, dem 1. Vorsitzenden des Imkervereins, überreicht.<br/>Am Ende der Veranstaltung wünschte der Vorsitzende allen Imkern und ihren Familien ein gesegnetes, besinnliches Weihnachtsfest sowie einen guten Start in das neue Jahr.</p>\n<p>Wer Interesse an heimischen Honig oder Imkerei hat, findet alle Infos unter www.bienenzuchtverein-gruenberg.de</p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('verpackungsgesetz', 'Verpackungsgesetz', '2018-11-30', NULL, NULL, '<p><strong>Merkblatt zum Verpackungsgesetz</strong></p>\n<p><strong> </strong></p>\n<p>Am 1. Januar 2019 tritt das Gesetz zur Fortentwicklung der haushaltsnahen Getrennterfassung von wertstoffhaltigen Abfällen (Verpackungsgesetz) in Kraft und löst damit die bisherige Verpackungsverordnung ab. Ziel ist eine Verpackungsentsorgung auf einer nachhaltigen und wettbewerbsneutralen Grundlage.</p>\n<p>VerpackV und VerpackG gelten für alle gewerbsmäßig einzustufenden Hersteller, die mit Ware befüllte und beim Endverbraucher anfallende Verpackungen in Verkehr bringen. Auch Online-Händler sind davon betroffen.</p>\n<p>Systembeteiligungspflichtige Verpackungen werden als mit Ware befüllte Verkaufs- und Umverpackungen definiert, die nach Gebrauch mehrheitlich beim Endverbrau- cher als Abfall anfallen; diese sind zu 100 Prozent bei entsprechenden Rücknahme- systemen zu lizenzieren.</p>\n<p>Gewerbsmäßig tätige Hersteller sind zukünftig dazu verpflichtet, sich vor dem Inver- kehrbringen von Verpackungen bei der neu geschaffenen Zentralen Stelle registrie- ren zu lassen. Ohne eine solche Registrierung dürfen Produkte in systembeteiligungspflichtigen Verpackungen nicht zum Verkauf angeboten werden.</p>\n<p>Ein Hersteller ist dabei derjenige Vertreiber (Inverkehrbringer), der verpackte Ware erstmalig gewerbsmäßig in den Verkehr bringt. Imker, die 30 Völker als Liebhaberei (Hobby) bewirtschaften, sind keine gewerbsmäßigen Hersteller.</p>\n<p>Die Zentrale Stelle Verpackungsregister stellt klar, dass derjenige, der Verpackungen lediglich im Rahmen eines „Hobbies“ befüllt und anschließend an Dritte abgibt, <strong>nicht </strong>von der Systembeteiligungspflicht nach § 7 VerpackG betroffen ist. Damit entfällt zu- gleich die Verpflichtung, sich gem. § 9 VerpackG bei der Zentralen Stelle zu registrieren und regelmäßige Meldungen gem. § 10 VerpackG abzugeben (vgl. <a href=\"https://www.verpackungsregister.org/fileadmin/files/FAQ/FAQ_Kleinstinverkehrbringer_gewerbsmaessiges_Inverkehrbringen.pdf\">https://www.verpackungsregister.org/fileadmin/files/FAQ/FAQ_Kleinstinverkehrbringe</a> <a href=\"https://www.verpackungsregister.org/fileadmin/files/FAQ/FAQ_Kleinstinverkehrbringer_gewerbsmaessiges_Inverkehrbringen.pdf\">r_gewerbsmaessiges_Inverkehrbringen.pdf</a>).</p>\n<p>Gewerbsmäßig ist jede auf Gewinnerzielung gerichtete angelegte selbständige Tä- tigkeit. Nach der Regelung des § 13 a EStG von 2015 sind die Imkereien bis zu 30 Völkern steuerfrei, da hier kein Gewinn erzielt werden kann. Es liegt somit keine Ge- winnnerzielungsabsicht vor. Bis zu diesem Bereich liegt somit keine Gewerbsmäßig- keit vor, sondern es geht um reine Liebhaberei. Der Honig, der verkauft wird, dient dazu einen Teil des Aufwandes für dieses Hobby zu decken.</p>\n<p>Diejenigen Imker, die ihre Tätigkeit gewerbsmäßig ausüben (Gewinnerzielungsabsicht, Verluste werden steuerlich geltend gemacht), haben zunächst grundsätzlich sämtliche Herstellerpflichten nach dem neuen VerpackungsG zu erfüllen. Es bleibt jedoch die Befreiung von der Systembeteiligungspflicht erhalten, wenn eine <strong>Mehr- wegverpackung </strong>(§ 12 Nr. 1 VerpackG) oder eine vorlizensierte <strong>Serviceverpackung </strong>(§ 7 VerpackG) verwendet wird.</p>\n<p> </p>\n<p>In § 12 werden grundsätzlich Mehrwegverpackungen von der Lizensierungspflicht ausgenommen. Es wird nicht näher beschrieben, ob dies nun explizit Pfandverpa- ckungen sein müssen. Aber: Es muss eine Wiedererkennbarkeit der Verpackung vorhanden und ein Mehrwegsystem sichergestellt sein sowie möglichst ein Anreizsystem zur Rückgabe geschaffen werden. Pfand schafft diesen zusätzlichen An- reiz das Glas zurückzubringen und sollte daher überall dort, wo es möglich ist, einge- führt werden. Zudem muss auf dem Glas selbst diese Möglichkeit „Mehrweg- oder Mehrweg-Pfandglas bzw. Pfandglas“ vorhanden sein. Früher genügte dieser Hinweis am Verkaufsort, dies reicht nicht mehr aus. In den Gewährverschluss können die Be- griffe eingedruckt werden.</p>\n<p>Wenn die Bezeichnung Pfandglas angegeben wird, muss auch Pfand genommen und rückerstattet werden.</p>\n<p>Zumindest die Möglichkeit der Rücknahme kann auch an anderen Verkaufsstellen als nur bei Privatverkauf eingerichtet werden. Ein aufgestellter Korb mit einem Schild</p>\n<p>„Hier Rückgabe“ reicht dazu schon aus. Dies ist sogar in den Supermärkten in den Regionalecken, wo der Honig der Imker meist verkauft wird, oft problemlos möglich. Viele Geschäfte wie Bäckereien, Metzgereien, Getränkemärkte, Postfilialen sind aber auch durchaus bereit, die Gläser gegen Pfand zu verkaufen und zurück zu nehmen. Hier ist es eine Verhandlungssache.</p>\n<p>Das Imker-Honigglas hat einen hohen Wiedererkennungswert und wird schon per se als ein Mehrwegglas angesehen.</p>\n<p>Bei dem 30 g Glas und den Verpackungen (Tragetaschen, Geschenkkartons), die der Deutsche Imkerbund verkauft erfolgt eine Vorlizenzierung durch den Deutschen Imkerbund e.V. Somit ist eine Verwendung sowohl für gewerbsmäßige als auch Hobby-Imker ohne zusätzlichen Kostenaufwand gegeben.</p>\nRegistrierung\n<p>Bei sämtlichen Verkäufen ohne Rücknahmemöglichkeit wie bspw. auch bei Internet- verkäufen spielt zunächst die Frage der Gewerbsmäßigkeit im Sinne des Verpa- ckungsgesetzes eine Rolle. Ist die Gewerbsmäßigkeit (z. B. ab 31 Völker) gegeben, muss eine Lizenzierung erfolgen. Auf der Seite <a href=\"https://www.ihk-ve-register.de/inhalt/duale_systeme\">https://www.ihk-ve-</a> <a href=\"https://www.ihk-ve-register.de/inhalt/duale_systeme\">register.de/inhalt/duale_systeme </a>befindet sich eine Übersicht über Lizenzierungsmöglichkeiten.</p>\nRückmeldung an den D.I.B.\n<p>Die oben genannten Ausführungen beruhen auf den Ausführungen der Zentralen Stelle Verpackungsregister sowie den dem D.I.B. schriftlich vorliegenden Stellung- nahmen der Ministerien von „Umwelt, Naturschutz und nukleare Sicherheit“ und „Er- nährung und Landwirtschaft“. Sollte es trotz der eindeutigen Auslegungen in den Im- kereien zu Problemen bei etwaigen Kontrollen der Ordnungsbehörden oder der zent- ralen Stelle Verpackungsregister kommen, bitten wir um Mitteilung an die Geschäfts- stelle.</p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('spannender', 'Spannender Jahresauftakt im Bienenzuchtverein Grünberg', '2018-06-02', NULL, NULL, '<p><strong>Spannender Jahresauftakt im Bienenzuchtverein Grünberg</strong></p>\n<p>Durch die verschneite Winterlandschaft machte sich der Bienenzuchtverein Grünberg und Umgebung e.V. Anfang Februar auf den Weg nach Erlensee. Dort erwartete die interessierte Imkergruppe aus Mittelhessen eine Führung durch die Berufsimkerei Ullmann. Begleitet wurde diese durch den Herrn des Hauses, Matthias Ullman, sowie einen Mitarbeiter. Sie erklärten ausführlich, wie man eine Imkerei mit 1000 Bienenvölkern erfolgreich führt und sorgten mit Erzählungen aus ihrem Arbeitsleben für das ein oder andere Staunen und Schmunzeln bei den Anwesenden. Natürlich erkannten die Hobbyimker während der Führung durch bis an die Decke geflieste Arbeitsräume für Schleuderung und Abfüllung sowie Räume mit Stapeln an leeren Bienenbehausungen, bereits gerichtet für das kommende Frühjahr, auch den einen oder anderen Arbeitsablauf aus der heimischen Imkerei. Doch die Dimensionen der Honigerzeugung ließ manchen sprachlos zurück. Den Gedanken an den Kauf einer Honigschleuder, in deren Halterungen 4 honigbefüllte Kisten (auch Zargen genannt) zeitgleich Platz finden, um das flüssige Gold aus ihnen heraus zu holen, können die meisten Hobbyimker getrost verwerfen – würde sich eine solche Investition nur bei entsprechend hoher Zahl an Bienenvölkern lohnen! Im weiteren Verlauf erzählte Herr Ullmann über die Wanderungen mit seinen Bienenstöcken durch ganz Deutschland und darüber, dass auch bei einer so großen Zahl an Völkern jede einzelne Biene wichtig ist und nach Möglichkeit für das Wohlbefinden aller Bienen zu sorgen ist. Zustimmung bei den Anwesenden Imkern erhielt er weiterhin für seine Einstellung, auch als Berufsimker bei der Wanderung mit seinen Bienen möglichst immer mit den örtlichen Hobbyimkern zusammen zu arbeiten.</p>\n<p>Nach diesem lehrreichen Ausflug, den der eine oder andere auf der Heimfahrt nach Grünberg noch einmal Revue passieren ließ, gab es nur eine kurze Pause. Der Imkerverein lud nämlich in der darauffolgenden Woche zu einem Vortrag von Dr. Giuseppe Bosco in die Condomer Stuben der Gallushalle ein. Hierbei brachte Dr. Bosco, Amtsveterinär des Lahn-Dill-Kreises und in diesem Rahmen zuständig für Bienengesundheit, den teilnehmenden Imkern anschaulich die aktuelle Situation der Faulbrut und die Methoden der Bekämpfung durch die Veterinäre nah. Weiterhin beschäftigte er sich in seinem Vortrag mit dem kleinen Beutenkäfer, der zwar momentan kein Problem für die Bienen der Grünberger Imker darstellt, seiner Meinung nach jedoch noch den Weg nach Deutschland finden wird. Schließlich ging der Referent auf die aktuelle Publikation zur Möglichkeit der Varroabekämpfung mittels Lithiumchlorid ein und mahnte die Anwesenden zur Geduld, da noch weiter an dieser Lösung geforscht werden müsse. Die bewährten Bekämpfungsmethoden seien auch weiterhin aktuell und für ihre Zwecke gut geeignet. Damit endete auch diese äußerst interessante Veranstaltung des Bienenzuchtvereins.</p>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('koeniginnezucht-einfach-erklaert', 'Königinnezucht einfach erklärt', '2026-05-14', NULL, 'news/2026/f2f5df3b46bd0501.jpg', '<div>Statt einer Monatsversammlung trafen wir uns diesmal am Bienenstand von Marco Herzberger. Dort erhielten wir eine anschauliche und praxisnahe Einführung in die einfache Königinnenzucht. Marco Herzberger erklärte die einzelnen Schritte verständlich und gab wertvolle Einblicke aus seiner Erfahrung. So wurde der Abend zu einer interessanten und lehrreichen Veranstaltung direkt am Bienenstand.&nbsp;</div>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('gruenberg-auf-der-rolle-2026', 'Grünberg auf der Rolle 2026', '2026-06-04', NULL, 'news/2026/0cbca3146e6cdf20.jpg', '<div>Bienenzuchtverein informierte bei „Grünberg auf der Rolle“</div><div>Bei der Veranstaltung „Grünberg auf der Rolle“ war auch der Bienenzuchtverein mit einem Infostand vertreten. Zahlreiche Besucherinnen und Besucher nutzten die Gelegenheit, sich über Honigbienen, Imkerei und die Bedeutung der Bestäubung für Natur und Landwirtschaft zu informieren.</div><div>Am Stand des Vereins erhielten Interessierte Einblicke in das Leben eines Bienenvolkes und erfuhren, welche Aufgaben Imkerinnen und Imker im Jahresverlauf übernehmen. Themen waren unter anderem die Honiggewinnung, bienenfreundliche Pflanzen sowie Möglichkeiten, wie jeder im eigenen Garten oder auf dem Balkon etwas zum Schutz von Bienen und anderen Insekten beitragen kann.</div><div>Besonders bei Familien und Kindern stieß der Infostand auf großes Interesse. Fragen wie „Wie entsteht Honig?“, „Woran erkennt man die Königin?“ oder „Warum sind Bienen so wichtig?“ wurden anschaulich beantwortet.<br><figure data-trix-attachment=\"{&quot;contentType&quot;:&quot;image/jpeg&quot;,&quot;filename&quot;:&quot;WhatsApp Image 2026-06-04 at 13.19.38.jpeg&quot;,&quot;filesize&quot;:353104,&quot;height&quot;:2048,&quot;href&quot;:&quot;/bilder/editor/6908dd152b6f9f8a.jpg&quot;,&quot;url&quot;:&quot;/bilder/editor/6908dd152b6f9f8a.jpg&quot;,&quot;width&quot;:1536}\" data-trix-content-type=\"image/jpeg\" data-trix-attributes=\"{&quot;presentation&quot;:&quot;gallery&quot;}\" class=\"attachment attachment--preview attachment--jpeg\"><a href=\"/bilder/editor/6908dd152b6f9f8a.jpg\"><img src=\"/bilder/editor/6908dd152b6f9f8a.jpg\" width=\"1536\" height=\"2048\"><figcaption class=\"attachment__caption\"><span class=\"attachment__name\">WhatsApp Image 2026-06-04 at 13.19.38.jpeg</span> <span class=\"attachment__size\">344.83 KB</span></figcaption></a></figure></div><div>Der Bienenzuchtverein zeigte sich erfreut über die vielen Gespräche und das große Interesse der Besucherinnen und Besucher. Die Teilnahme an „Grünberg auf der Rolle“ war für den Verein eine gute Gelegenheit, auf die Bedeutung der regionalen Imkerei und den Schutz der Bienen aufmerksam zu machen.</div>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('asiatische-hornisse', 'Asiatische Hornisse', '2026-06-14', NULL, 'news/2026/b80e2ce41c2fe82a.png', '<div><strong>In Grünberg wurde erstmals eine Asiatische Hornissen-Königin (Vespa velutina)* entdeckt und fachgerecht beseitigt.</strong><br><br>Die Königin war bereits dabei, ein *Primärnest (ca. 2–3 cm)* zu bauen – ein typischer Entwicklungsstand für Ende April.<br>Durch das schnelle Eingreifen konnte verhindert werden, dass sich im Sommer ein großes *Sekundärnest mit vielen hundert Tieren* bildet.<br><br> Wichtig für alle Bürgerinnen und Bürger:*<br>Wo eine Königin gefunden wurde, sind *weitere in der Umgebung sehr wahrscheinlich*!<br><br>Besonders aufmerksam sein im Bereich:<br> Theo-Koch-Schule<br> Kita Zauberwald<br> Wohnmobilpark „Grünberg Campingground“<br><br><strong>So erkennen Sie die Asiatische Hornisse:</strong><br> überwiegend *schwarz*<br> gelbe Beine* („gelbe Füße“)<br> orange-rötlicher Ring* am Hinterleib<br><br>Bitte helfen Sie mit!<br>Verdächtige Sichtungen *fotografieren* und direkt an den Imkerverein Grünberg melden.<br>oder an das&nbsp;</div><h1><a href=\"https://www.hlnug.de/themen/naturschutz/tiere-und-pflanzen/arten-melden/hornisse\">Hessisches Landesamt für Naturschutz, Umwelt und Geologie</a></h1><div><br><br>❗ *Wichtig:*<br>Nicht selbst bekämpfen!<br>Die heimische Hornisse ist geschützt und darf nicht verwechselt werden.</div>', 1);
INSERT INTO `news` (`slug`, `title`, `published_at`, `expires_at`, `image_path`, `body`, `is_published`) VALUES ('bienenschwarm', 'Bienenschwarm', '2026-05-17', NULL, 'news/2026/05229c069beb899e.jpg', '<div>Am 17.05. wurde von Vereinsmitgliedern des Imkervereins Grünberg ein Bienenschwarm an der Eisdiele am Grünberger Marktplatz eingefangen.</div><div>Der Schwarm hatte sich auf einem Sonnenschirm niedergelassen. Ein Bienenschwarm ist in der Regel nicht gefährlich. Schwarmbienen sind meist friedlich, da sie kein Nest verteidigen. Trotzdem sollte man Abstand halten und den Schwarm nicht stören.</div><div>Bei Sichtung eines Schwarms bitte den Imkerverein Grünberg informieren.</div>', 1);
