INSERT INTO `infos` (`section`, `title`, `body`, `link_url`, `download_path`, `sort_order`, `is_published`) VALUES ('recht', 'Honigverordnung Neu', '<div>Artikel 1 ändert die <strong>Honigverordnung</strong>. Er gilt ab <strong>14. Juni 2026</strong>. Alte Ware, die vorher korrekt hergestellt und gekennzeichnet wurde, darf noch verkauft werden, bis die Bestände aufgebraucht sind.&nbsp;</div><div>Verständlich übersetzt</div><div>1. Die Regeln gelten nicht mehr nur für „gewerbsmäßiges“ Inverkehrbringen</div><div>Das Wort <strong>„gewerbsmäßig“</strong> wird gestrichen. Praktisch heißt das: Die Honigverordnung wird sprachlich breiter gefasst. Es geht nicht mehr nur ausdrücklich um gewerbsmäßiges Inverkehrbringen.&nbsp;</div><div>2. Herkunftsangabe bei Honig wird strenger</div><div>Bei Honig muss künftig angegeben werden, <strong>aus welchem Ursprungsland</strong> er kommt. Bei Mischhonig aus mehreren Ländern reicht eine pauschale Angabe wie „Mischung von Honig aus EU- und Nicht-EU-Ländern“ nicht mehr in dieser Form aus. Stattdessen müssen die Ursprungsländer <strong>in absteigender Reihenfolge</strong> genannt werden, zusammen mit dem jeweiligen <strong>Gewichtsanteil in Prozent</strong>, und zwar im Hauptsichtfeld des Etiketts.&nbsp;</div><div>Beispiel in normaler Sprache:</div><blockquote>Nicht mehr nur: „Honig aus EU- und Nicht-EU-Ländern“<br>&nbsp;Sondern etwa: „Ukraine 60 %, Deutschland 25 %, Argentinien 15 %“</blockquote><div>Für diese Prozentangaben gibt es eine <strong>Toleranz von 5 Prozentpunkten</strong>, weil Mischungen in der Praxis nicht immer exakt auf den Punkt gleich ausfallen.&nbsp;</div><div>Bei sehr kleinen Packungen unter <strong>30 g Nettofüllmenge</strong> dürfen statt ausgeschriebener Ländernamen auch zweibuchstabige Ländercodes verwendet werden, zum Beispiel „DE“ für Deutschland.&nbsp;</div><div>3. „Backhonig“ wird neu gefasst</div><div>Die Kategorie <strong>Backhonig</strong> wird neu beschrieben. Gemeint ist Honig, der nicht als normaler Speisehonig gedacht ist, sondern für industrielle Zwecke oder als Zutat in weiterverarbeiteten Lebensmitteln. Er darf zum Beispiel fremden Geschmack oder Geruch haben, gegoren sein, überhitzt worden sein oder so behandelt worden sein, dass Pollen in erheblichem Maß entfernt wurden.&nbsp;</div><div>Wichtig: Solcher Honig muss mit dem Hinweis <strong>„nur zum Kochen und Backen“</strong> gekennzeichnet werden.&nbsp;</div><div>4. „Gefilterter Honig“ verschwindet als eigene Kategorie</div><div>Die bisherige Nummer 9 in Anlage 1 wird gestrichen. Außerdem wird in Anlage 2 der Begriff <strong>„gefilterter Honig“</strong> durch <strong>„Backhonig“</strong> ersetzt.&nbsp;</div><div>In Klartext: Was früher rechtlich als „gefilterter Honig“ separat auftauchte, wird in diesem Änderungspaket nicht mehr als eigene Kategorie weitergeführt, sondern in Richtung Backhonig-Regelung verschoben.</div><div>5. Verstöße werden angepasst</div><div>Die Straf- und Bußgeldregelungen werden neu gefasst. Wer Honig entgegen den Verkehrsverboten in Verkehr bringt, kann strafbar handeln; andere Verstöße können als Ordnungswidrigkeit geahndet werden.&nbsp;</div><div>Kurz gesagt</div><div>Artikel 1 sorgt vor allem für <strong>mehr Transparenz bei Honig-Herkunft</strong>. Bei Mischhonig müssen die Herkunftsländer künftig konkret mit Prozentanteilen aufs Etikett. Außerdem wird <strong>Backhonig</strong> klarer geregelt, und die alte Kategorie <strong>gefilterter Honig</strong> fällt weg beziehungsweise wird in der Systematik ersetzt.</div>', 'https://www.recht.bund.de/bgbl/1/2025/289/regelungstext.pdf?__blob=publicationFile&v=3', '', 10, 1);
INSERT INTO `infos` (`section`, `title`, `body`, `link_url`, `download_path`, `sort_order`, `is_published`) VALUES ('recht', 'Kennzeichnung von Honig', '<div><strong>PflichtangabeBeispielLebensmittelbezeichnung</strong> | „Honig“, „Blütenhonig“, „Waldhonig“, „Lindenhonig“<br><strong>Ursprungsland</strong> | „Deutschland“ oder „Ursprung: Deutschland“<br><strong>Nettofüllmenge</strong> | „250 g“, „500 g“<br><strong>Mindesthaltbarkeitsdatum</strong> | „Mindestens haltbar bis: 31.12.2027“<br><strong>Los-/Chargennummer</strong> | „Los: 2026-01“; entfällt oft, wenn das MHD taggenau ist<br><strong>Name/Firma und Anschrift</strong> | Name der Imkerei + ladungsfähige Adresse<br><strong>Lagerhinweis</strong> | z. B. „Trocken, kühl und lichtgeschützt lagern“<br><strong>Kennzeichnung gut lesbar auf Deutsch</strong> | Pflichtangaben dürfen nicht versteckt oder schlecht lesbar sein.<br><br> Bei Sortenbezeichnungen wie „Lindenhonig“, „Rapsblütenhonig“ oder „Waldhonig“ muss der Honig diese Herkunft beziehungsweise Eigenschaften auch tatsächlich überwiegend haben. Die Honigverordnung erlaubt solche Ergänzungen nur, wenn die entsprechenden Merkmale vorliegen&nbsp;</div>', NULL, '', 20, 1);
